import { eq } from 'drizzle-orm'
import { db } from '../db/index.js'
import { agentSessions } from '../db/schema/agent-sessions.js'
import { agentMessages } from '../db/schema/agent-messages.js'
import { agentLogs } from '../db/schema/agent-logs.js'
import { bridgeRegistry } from '../bridges/index.js'
import type { AgentExecutionContext, AgentStreamCallback, AgentExecutionResult } from './types.js'

export class AgentExecutor {
  private activeExecutions = new Map<string, boolean>()

  async execute(context: AgentExecutionContext, callbacks: AgentStreamCallback): Promise<AgentExecutionResult> {
    const bridge = bridgeRegistry.get(context.bridgeName)
    if (!bridge) {
      const error = `Bridge "${context.bridgeName}" not found`
      await this.failSession(context.sessionId, error)
      callbacks.onError(error)
      return { status: 'failed', output: '', error }
    }

    if (!bridge.isAvailable()) {
      const error = `Bridge "${context.bridgeName}" is not available`
      await this.failSession(context.sessionId, error)
      callbacks.onError(error)
      return { status: 'failed', output: '', error }
    }

    this.activeExecutions.set(context.sessionId, true)

    await db
      .update(agentSessions)
      .set({ status: 'running', updatedAt: new Date() })
      .where(eq(agentSessions.id, context.sessionId))

    callbacks.onStatus('running')
    await this.addLog(context.sessionId, 'status', 'Execution started')

    try {
      const result = await bridge.streamResponse(
        {
          sessionId: context.sessionId,
          projectId: context.projectId,
          prompt: context.prompt,
        },
        (event) => {
          if (!this.activeExecutions.get(context.sessionId)) return

          switch (event.type) {
            case 'output':
              callbacks.onOutput(event.content)
              break
            case 'error':
              callbacks.onError(event.content)
              break
            case 'status':
              callbacks.onLog('bridge', event.content)
              break
            case 'complete':
              callbacks.onLog('bridge', event.content)
              break
          }
        },
      )

      if (!this.activeExecutions.get(context.sessionId)) {
        return { status: 'cancelled', output: '' }
      }

      await db.insert(agentMessages).values({
        sessionId: context.sessionId,
        role: 'agent',
        content: result.output,
      })

      await db
        .update(agentSessions)
        .set({ status: 'completed', updatedAt: new Date() })
        .where(eq(agentSessions.id, context.sessionId))

      await this.addLog(context.sessionId, 'status', 'Execution completed')

      const executionResult: AgentExecutionResult = {
        status: 'completed',
        output: result.output,
      }

      callbacks.onComplete(executionResult)
      this.activeExecutions.delete(context.sessionId)
      return executionResult
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown error'
      await this.failSession(context.sessionId, errorMessage)
      callbacks.onError(errorMessage)
      this.activeExecutions.delete(context.sessionId)
      return { status: 'failed', output: '', error: errorMessage }
    }
  }

  async cancel(sessionId: string): Promise<void> {
    this.activeExecutions.delete(sessionId)

    const bridges = bridgeRegistry.getAll()
    for (const bridge of bridges) {
      await bridge.cancelExecution(sessionId)
    }

    await db
      .update(agentSessions)
      .set({ status: 'cancelled', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))

    await this.addLog(sessionId, 'status', 'Execution cancelled')
  }

  isRunning(sessionId: string): boolean {
    return this.activeExecutions.get(sessionId) === true
  }

  private async failSession(sessionId: string, error: string): Promise<void> {
    await db
      .update(agentSessions)
      .set({ status: 'failed', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))

    await this.addLog(sessionId, 'error', error)
  }

  private async addLog(sessionId: string, logType: string, message: string): Promise<void> {
    await db.insert(agentLogs).values({ sessionId, logType, message })
  }
}

export const agentExecutor = new AgentExecutor()

export type AgentStatus = 'idle' | 'running' | 'completed' | 'failed' | 'cancelled'

export interface AgentExecutionContext {
  sessionId: string
  projectId: string
  prompt: string
  bridgeName: string
}

export interface AgentExecutionResult {
  status: AgentStatus
  output: string
  error?: string
}

export interface AgentStreamCallback {
  onOutput: (content: string) => void
  onStatus: (status: AgentStatus) => void
  onLog: (logType: string, message: string) => void
  onComplete: (result: AgentExecutionResult) => void
  onError: (error: string) => void
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { api } from '@/lib/api'
import type { Project, CreateProjectInput, UpdateProjectInput } from '@/types'

export function useProjects() {
  const queryClient = useQueryClient()

  const { data: projects, isLoading } = useQuery({
    queryKey: ['projects'],
    queryFn: () => api.get<Project[]>('/projects'),
  })

  const createMutation = useMutation({
    mutationFn: (input: CreateProjectInput) =>
      api.post<Project>('/projects', input),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['projects'] })
    },
  })

  const updateMutation = useMutation({
    mutationFn: ({ id, ...data }: UpdateProjectInput & { id: string }) =>
      api.patch<Project>(`/projects/${id}`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['projects'] })
    },
  })

  const deleteMutation = useMutation({
    mutationFn: (id: string) =>
      api.delete(`/projects/${id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['projects'] })
    },
  })

  return {
    projects: projects ?? [],
    isLoading,
    createProject: createMutation.mutateAsync,
    isCreating: createMutation.isPending,
    createError: createMutation.error,
    updateProject: updateMutation.mutateAsync,
    isUpdating: updateMutation.isPending,
    updateError: updateMutation.error,
    deleteProject: deleteMutation.mutateAsync,
    isDeleting: deleteMutation.isPending,
    deleteError: deleteMutation.error,
  }
}

export function useProject(id: string) {
  const { data: project, isLoading } = useQuery({
    queryKey: ['projects', id],
    queryFn: () => api.get<Project>(`/projects/${id}`),
    enabled: !!id,
  })

  return {
    project: project ?? null,
    isLoading,
  }
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { api } from '@/lib/api'
import type { AgentSession, AgentSessionWithMessages, AgentMessage, AgentLog } from '@/types'

export function useAgentSessions(projectId: string) {
  const queryClient = useQueryClient()

  const { data: sessions, isLoading } = useQuery({
    queryKey: ['projects', projectId, 'agent', 'sessions'],
    queryFn: () => api.get<AgentSession[]>(`/projects/${projectId}/agent/sessions`),
    enabled: !!projectId,
  })

  const createSessionMutation = useMutation({
    mutationFn: () =>
      api.post<AgentSession>(`/projects/${projectId}/agent/sessions`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['projects', projectId, 'agent', 'sessions'] })
    },
  })

  const cancelSessionMutation = useMutation({
    mutationFn: (sessionId: string) =>
      api.post<AgentSession>(`/projects/${projectId}/agent/sessions/${sessionId}/cancel`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['projects', projectId, 'agent', 'sessions'] })
    },
  })

  return {
    sessions: sessions ?? [],
    isLoading,
    createSession: createSessionMutation.mutateAsync,
    isCreatingSession: createSessionMutation.isPending,
    cancelSession: cancelSessionMutation.mutateAsync,
    isCancellingSession: cancelSessionMutation.isPending,
  }
}

export function useAgentSession(projectId: string, sessionId: string) {
  const queryClient = useQueryClient()

  const { data: session, isLoading } = useQuery({
    queryKey: ['projects', projectId, 'agent', 'sessions', sessionId],
    queryFn: () => api.get<AgentSessionWithMessages>(`/projects/${projectId}/agent/sessions/${sessionId}`),
    enabled: !!projectId && !!sessionId,
    refetchInterval: (query) => {
      const data = query.state.data
      if (data && (data.status === 'running' || data.status === 'idle')) {
        return 2000
      }
      return false
    },
  })

  const sendMessageMutation = useMutation({
    mutationFn: (content: string) =>
      api.post<AgentMessage>(`/projects/${projectId}/agent/sessions/${sessionId}/messages`, { content }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['projects', projectId, 'agent', 'sessions', sessionId] })
    },
  })

  return {
    session: session ?? null,
    messages: session?.messages ?? [],
    isLoading,
    sendMessage: sendMessageMutation.mutateAsync,
    isSending: sendMessageMutation.isPending,
    sendError: sendMessageMutation.error,
  }
}

export function useAgentLogs(projectId: string, sessionId: string) {
  const { data: logs, isLoading } = useQuery({
    queryKey: ['projects', projectId, 'agent', 'sessions', sessionId, 'logs'],
    queryFn: () => api.get<AgentLog[]>(`/projects/${projectId}/agent/sessions/${sessionId}/logs`),
    enabled: !!projectId && !!sessionId,
    refetchInterval: 3000,
  })

  return {
    logs: logs ?? [],
    isLoading,
  }
}

