                  isDeleting ? 'bg-destructive/70' : 'bg-destructive hover:bg-destructive/90'
                )}
              >
                {isDeleting ? 'Deleting...' : 'Delete'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}
","referencedBy":{}},{"path":"client/src/pages/workspace.tsx","content":"import { useState, useRef, useEffect, useCallback } from 'react'
import { Link, useParams } from 'react-router'
import Editor from '@monaco-editor/react'
import {
  ArrowLeft,
  ChevronRight,
  ChevronDown,
  File,
  Folder,
  Play,
  Settings,
  Send,
  MessageSquare,
  Bot,
  User,
  Loader2,
  AlertCircle,
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { useProject } from '@/hooks/use-projects'
import { useAgentSessions, useAgentSession } from '@/hooks/use-agent'

interface FileNode {
  name: string
  type: 'file' | 'folder'
  children?: FileNode[]
}

const mockFileTree: FileNode[] = [
  {
    name: 'src',
    type: 'folder',
    children: [
      {
        name: 'main',
        type: 'folder',
        children: [
          {
            name: 'java',
            type: 'folder',
            children: [
              {
                name: 'com.example.plugin',
                type: 'folder',
                children: [
                  { name: 'Main.java', type: 'file' },
                  { name: 'CommandHandler.java', type: 'file' },
                  { name: 'EventListener.java', type: 'file' },
                ],
              },
            ],
          },
          {
            name: 'resources',
            type: 'folder',
            children: [
              { name: 'plugin.yml', type: 'file' },
              { name: 'config.yml', type: 'file' },
            ],
          },
        ],
      },
    ],
  },
  { name: 'build.gradle', type: 'file' },
  { name: 'README.md', type: 'file' },
]

const placeholderCode = `package com.example.plugin;

import org.bukkit.plugin.java.JavaPlugin;

public class Main extends JavaPlugin {

    @Override
    public void onEnable() {
        getLogger().info("Plugin enabled!");
        // Register commands and events here
    }

    @Override
    public void onDisable() {
        getLogger().info("Plugin disabled!");
    }
}
`

function FileTreeNode({ node, depth = 0, selectedFile, onSelect }: {
  node: FileNode
  depth?: number
  selectedFile: string
  onSelect: (name: string) => void
}) {
  const [open, setOpen] = useState(depth < 3)

  return (
    <div>
      <button
        onClick={() => {
          if (node.type === 'folder') {
            setOpen(!open)
          } else {
            onSelect(node.name)
          }
        }}
        className={cn(
          'flex w-full items-center gap-1.5 rounded px-2 py-1 text-left text-xs transition-colors hover:bg-surface-hover',
          node.type === 'file' && node.name === selectedFile
            ? 'bg-primary/10 text-primary'
            : node.type === 'file'
              ? 'text-text-muted'
              : 'text-text'
        )}
        style={{ paddingLeft: `${depth * 12 + 8}px` }}
      >
        {node.type === 'folder' ? (
          open ? <ChevronDown className="h-3 w-3 shrink-0 text-text-dim" /> : <ChevronRight className="h-3 w-3 shrink-0 text-text-dim" />
        ) : (
          <span className="w-3" />
        )}
        {node.type === 'folder' ? (
          <Folder className="h-3.5 w-3.5 shrink-0 text-primary/70" />
        ) : (
          <File className="h-3.5 w-3.5 shrink-0 text-text-dim" />
        )}
        <span className="truncate">{node.name}</span>
      </button>
      {node.type === 'folder' && open && node.children?.map((child) => (
        <FileTreeNode
          key={child.name}
          node={child}
          depth={depth + 1}
          selectedFile={selectedFile}
          onSelect={onSelect}
        />
      ))}
    </div>
  )
}

function ChatPanel({ projectId }: { projectId: string }) {
  const { sessions, isLoading: sessionsLoading, createSession } = useAgentSessions(projectId)

  const initialSessionId = sessions.length > 0 ? sessions[0].id : null
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null)
  const resolvedSessionId = activeSessionId ?? initialSessionId

  if (sessionsLoading) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <Loader2 className="h-5 w-5 animate-spin text-text-dim" />
      </div>
    )
  }

  if (!resolvedSessionId) {
    return <ChatEmptyState onSessionCreated={setActiveSessionId} createSession={createSession} />
  }

  return <ChatSession projectId={projectId} sessionId={resolvedSessionId} />
}

function ChatEmptyState({ onSessionCreated, createSession }: {
  onSessionCreated: (id: string) => void
  createSession: () => Promise<{ id: string }>
}) {
  const [input, setInput] = useState('')
  const [isCreating, setIsCreating] = useState(false)

  const handleSend = async () => {
    const trimmed = input.trim()
    if (!trimmed || isCreating) return
    setIsCreating(true)
    try {
      const session = await createSession()
      onSessionCreated(session.id)
    } catch {
      setIsCreating(false)
    }
  }

  return (
    <>
      <div className="flex-1 overflow-y-auto p-4">
        <div className="flex flex-col items-center justify-center py-12 text-center">
          <div className="mb-3 rounded-xl bg-primary/10 p-3">
            <MessageSquare className="h-6 w-6 text-primary" />
          </div>
          <p className="text-sm font-medium text-text">Start a conversation</p>
          <p className="mt-1 text-xs text-text-dim">
            Describe what you want to build and the AI agent will help you create it.
          </p>
        </div>
      </div>
      <div className="border-t border-border p-3">
        <div className="flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend() } }}
            placeholder="Describe your plugin idea..."
            disabled={isCreating}
            className="flex-1 rounded-lg border border-border bg-background px-3 py-2 text-sm text-text placeholder:text-text-dim focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-50"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isCreating}
            className="rounded-lg bg-primary p-2 text-primary-foreground transition-colors hover:bg-primary-hover disabled:opacity-50"
          >
            {isCreating ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
          </button>
        </div>
      </div>
    </>
  )
}

function ChatSession({ projectId, sessionId }: { projectId: string; sessionId: string }) {
  const { session, messages, isLoading, sendMessage, isSending } = useAgentSession(projectId, sessionId)
  const [input, setInput] = useState('')
  const messagesEndRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  const handleSend = useCallback(async () => {
    const trimmed = input.trim()
    if (!trimmed || isSending) return
    setInput('')
    await sendMessage(trimmed)
  }, [input, isSending, sendMessage])

  if (isLoading) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <Loader2 className="h-5 w-5 animate-spin text-text-dim" />
      </div>
    )
  }

  const statusColor =
    session?.status === 'running' ? 'text-warning' :
    session?.status === 'completed' ? 'text-success' :
    session?.status === 'failed' ? 'text-destructive' :
    'text-text-dim'

  return (
    <>
      <div className="flex-1 overflow-y-auto p-4">
        {messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 text-center">
            <div className="mb-3 rounded-xl bg-primary/10 p-3">
              <MessageSquare className="h-6 w-6 text-primary" />
            </div>
            <p className="text-sm font-medium text-text">Session started</p>
            <p className="mt-1 text-xs text-text-dim">Send a message to begin.</p>
          </div>
        ) : (
          <div className="space-y-4">
            {messages.map((msg) => (
              <div key={msg.id} className="flex gap-2.5">
                <div className={cn(
                  'mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full',
                  msg.role === 'user' ? 'bg-primary/10' : 'bg-surface-hover'
                )}>
                  {msg.role === 'user'
                    ? <User className="h-3.5 w-3.5 text-primary" />
                    : <Bot className="h-3.5 w-3.5 text-text-muted" />}
                </div>
                <div className="min-w-0 flex-1">
                  <p className="text-xs font-medium text-text-muted">
                    {msg.role === 'user' ? 'You' : msg.role === 'system' ? 'System' : 'AI Agent'}
                  </p>
                  <p className="mt-0.5 whitespace-pre-wrap text-sm text-text">{msg.content}</p>
                </div>
              </div>
            ))}
            {isSending && (
              <div className="flex gap-2.5">
                <div className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-surface-hover">
                  <Loader2 className="h-3.5 w-3.5 animate-spin text-text-muted" />
                </div>
                <div>
                  <p className="text-xs font-medium text-text-muted">AI Agent</p>
                  <p className="mt-0.5 text-sm text-text-dim">Processing...</p>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>
      <div className="border-t border-border p-3">
        {session && session.status !== 'idle' && session.status !== 'running' && (
          <div className="mb-2 flex items-center gap-1.5 text-xs">
            <AlertCircle className={cn('h-3 w-3', statusColor)} />
            <span className={statusColor}>Session {session.status}</span>
          </div>
        )}
        <div className="flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend() } }}
            placeholder="Describe your plugin idea..."
            disabled={isSending}
            className="flex-1 rounded-lg border border-border bg-background px-3 py-2 text-sm text-text placeholder:text-text-dim focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary disabled:opacity-50"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isSending}
            className="rounded-lg bg-primary p-2 text-primary-foreground transition-colors hover:bg-primary-hover disabled:opacity-50"
          >
            {isSending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
          </button>
        </div>
      </div>
    </>
  )
}

export default function WorkspacePage() {
  const { projectId } = useParams<{ projectId: string }>()
  const { project, isLoading } = useProject(projectId ?? '')
  const [selectedFile, setSelectedFile] = useState('Main.java')

  if (isLoading) {
    return (
      <div className="flex h-screen items-center justify-center bg-background">
        <div className="flex flex-col items-center gap-3">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
          <p className="text-sm text-text-muted">Loading workspace...</p>
        </div>
      </div>
    )
  }

  if (!project) {
    return (
      <div className="flex h-screen flex-col items-center justify-center bg-background">
        <AlertCircle className="h-8 w-8 text-destructive" />
        <p className="mt-3 text-sm text-text-muted">Project not found</p>
        <Link to="/dashboard" className="mt-4 text-sm font-medium text-primary hover:text-primary-hover">
          Back to dashboard
        </Link>
      </div>
    )
  }

  return (
    <div className="flex h-screen flex-col bg-background">
      {/* Top bar */}
      <header className="flex h-12 items-center justify-between border-b border-border bg-surface px-4">
        <div className="flex items-center gap-3">
          <Link to="/dashboard" className="text-text-dim hover:text-text-muted">
            <ArrowLeft className="h-4 w-4" />
          </Link>
          <span className="text-sm font-medium text-text">{project.name}</span>
          <span className="rounded bg-accent px-2 py-0.5 text-xs text-text-dim">{project.software}</span>
          <span className="rounded bg-accent px-2 py-0.5 text-xs text-text-dim">{project.language}</span>
        </div>
        <div className="flex items-center gap-2">
          <button
            className="inline-flex items-center gap-1.5 rounded-md bg-success/10 px-3 py-1.5 text-xs font-medium text-success opacity-50"
            disabled
          >
            <Play className="h-3 w-3" />
            Compile
          </button>
          <button className="rounded-md border border-border p-1.5 text-text-dim hover:text-text-muted">
            <Settings className="h-4 w-4" />
          </button>
        </div>
      </header>

      {/* Main workspace */}
      <div className="flex flex-1 overflow-hidden">
        {/* File tree */}
        <aside className="w-56 shrink-0 overflow-y-auto border-r border-border bg-surface py-2">
          <p className="mb-2 px-3 text-xs font-medium uppercase tracking-wider text-text-dim">
            Files
          </p>
          {mockFileTree.map((node) => (
            <FileTreeNode
              key={node.name}
              node={node}
              selectedFile={selectedFile}
              onSelect={setSelectedFile}
            />
          ))}
        </aside>

        {/* Editor */}
        <main className="flex-1 overflow-hidden">
          <div className="flex h-full flex-col">
            <div className="flex h-9 items-center border-b border-border bg-surface px-4">
              <div className="flex items-center gap-2 rounded bg-surface-hover px-2 py-1 text-xs text-text-muted">
                <File className="h-3 w-3" />
                {selectedFile}
              </div>
            </div>
            <div className="flex-1">
              <Editor
                height="100%"
                language="java"
                theme="vs-dark"
                value={placeholderCode}
                options={{
                  readOnly: true,
                  fontSize: 13,
                  minimap: { enabled: false },
                  scrollBeyondLastLine: false,
                  padding: { top: 12 },
                  lineNumbers: 'on',
                  renderLineHighlight: 'line',
                  cursorBlinking: 'smooth',
                  smoothScrolling: true,
                  fontFamily: "'JetBrains Mono', 'Fira Code', 'Cascadia Code', Menlo, monospace",
                  fontLigatures: true,
                }}
              />
            </div>
          </div>
        </main>

        {/* Chat panel */}
        <aside className="flex w-80 shrink-0 flex-col border-l border-border bg-surface">
          <div className="flex items-center gap-2 border-b border-border px-4 py-3">
            <MessageSquare className="h-4 w-4 text-primary" />
            <span className="text-sm font-medium text-text">AI Assistant</span>
          </div>
          <ChatPanel projectId={project.id} />
        </aside>
      </div>
    </div>
  )
}
","referencedBy":{}},{"path":"client/src/pages/new-project.tsx","content":"import { useState } from 'react'
import { useNavigate } from 'react-router'
import { ArrowLeft, ArrowRight, Check } from 'lucide-react'
import { cn } from '@/lib/utils'
import { useProjects } from '@/hooks/use-projects'

const steps = ['Project Info', 'Platform', 'Build Config', 'Source']

const softwareOptions = [
  { value: 'paper', label: 'Paper', description: 'High performance Minecraft fork' },
  { value: 'spigot', label: 'Spigot', description: 'Popular Bukkit fork' },
  { value: 'bukkit', label: 'Bukkit', description: 'Original modding API' },
  { value: 'velocity', label: 'Velocity', description: 'Modern proxy server' },
  { value: 'bungeecord', label: 'BungeeCord', description: 'Legacy proxy server' },
]

const javaVersions = ['21', '17', '11', '8']
const compilers = [
  { value: 'gradle', label: 'Gradle', description: 'Modern build tool (recommended)' },
  { value: 'maven', label: 'Maven', description: 'Traditional build tool' },
]

export default function NewProjectPage() {
  const navigate = useNavigate()
  const { createProject, isCreating } = useProjects()
  const [step, setStep] = useState(0)
  const [error, setError] = useState<string | null>(null)
  const [form, setForm] = useState({
    name: '',
    software: 'paper',
    language: 'java' as 'java' | 'kotlin',
    javaVersion: '21',
    compiler: 'gradle',
    source: 'blank' as 'blank' | 'zip' | 'github',
  })

  const canProceed = () => {
    switch (step) {
      case 0: return form.name.trim().length >= 2
      case 1: return !!form.software
      case 2: return !!form.compiler && !!form.javaVersion
      case 3: return !!form.source
      default: return false
    }
  }

  const handleCreate = async () => {
    setError(null)
    try {
      const project = await createProject({
        name: form.name.trim(),
        software: form.software,
        language: form.language,
        javaVersion: form.javaVersion,
        compiler: form.compiler as 'maven' | 'gradle',
      })
      navigate(`/workspace/${project.id}`)
    } catch (err: unknown) {
      const message = err !== null && typeof err === 'object' && 'message' in err
        ? String(err.message)
        : 'Failed to create project'
      setError(message)
    }
  }

  return (
    <div className="mx-auto max-w-2xl px-4 py-8 sm:px-6">
      <button
        onClick={() => navigate('/dashboard')}
        className="mb-6 inline-flex items-center gap-2 text-sm text-text-muted hover:text-text"
      >
        <ArrowLeft className="h-4 w-4" />
        Back to projects
      </button>

      <h1 className="text-2xl font-bold tracking-tight text-text">Create New Project</h1>
      <p className="mt-1 text-sm text-text-muted">Set up your Minecraft plugin project</p>

      {/* Step indicators */}
      <div className="mt-8 flex items-center gap-2">
        {steps.map((label, i) => (
          <div key={label} className="flex flex-1 items-center gap-2">
            <div
              className={cn(
                'flex h-8 w-8 shrink-0 items-center justify-center rounded-full text-xs font-medium transition-colors',
                i < step
                  ? 'bg-primary text-primary-foreground'
                  : i === step
                    ? 'border-2 border-primary text-primary'
                    : 'border border-border text-text-dim'
              )}
            >
              {i < step ? <Check className="h-4 w-4" /> : i + 1}
            </div>
            <span className={cn(
              'hidden text-xs sm:block',
              i === step ? 'text-text' : 'text-text-dim'
            )}>
              {label}
            </span>
            {i < steps.length - 1 && (
              <div className={cn(
                'h-px flex-1',
                i < step ? 'bg-primary' : 'bg-border'
              )} />
            )}
          </div>
        ))}
      </div>

      {/* Step content */}
      <div className="mt-8 rounded-xl border border-border bg-surface p-6">
        {step === 0 && (
          <div className="space-y-4">
            <div>
              <label className="mb-1.5 block text-sm font-medium text-text">Project Name</label>
              <input
                type="text"
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm text-text placeholder:text-text-dim focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                placeholder="MyAwesomePlugin"
              />
            </div>
            <div>
              <label className="mb-1.5 block text-sm font-medium text-text">Project Type</label>
              <div className="rounded-lg border border-primary bg-primary/5 px-4 py-3">
                <p className="text-sm font-medium text-text">Minecraft Plugin</p>
                <p className="text-xs text-text-muted">Server-side plugin for Minecraft Java Edition</p>
              </div>
            </div>
          </div>
        )}

        {step === 1 && (
          <div className="space-y-4">
            <div>
              <label className="mb-3 block text-sm font-medium text-text">Server Software</label>
              <div className="space-y-2">
                {softwareOptions.map((sw) => (
                  <button
                    key={sw.value}
                    onClick={() => setForm({ ...form, software: sw.value })}
                    className={cn(
                      'flex w-full items-center gap-3 rounded-lg border px-4 py-3 text-left transition-colors',
                      form.software === sw.value
                        ? 'border-primary bg-primary/5'
                        : 'border-border hover:border-border-bright hover:bg-surface-hover'
                    )}
                  >
                    <div className={cn(
                      'flex h-4 w-4 shrink-0 items-center justify-center rounded-full border',
                      form.software === sw.value
                        ? 'border-primary bg-primary'
                        : 'border-border'
                    )}>
                      {form.software === sw.value && <div className="h-2 w-2 rounded-full bg-white" />}
                    </div>
                    <div>
                      <p className="text-sm font-medium text-text">{sw.label}</p>
                      <p className="text-xs text-text-muted">{sw.description}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <div>
              <label className="mb-3 block text-sm font-medium text-text">Language</label>
              <div className="flex gap-3">
                {(['java', 'kotlin'] as const).map((lang) => (
                  <button
                    key={lang}
                    onClick={() => setForm({ ...form, language: lang })}
                    className={cn(
                      'flex-1 rounded-lg border px-4 py-3 text-sm font-medium transition-colors',
                      form.language === lang
                        ? 'border-primary bg-primary/5 text-text'
                        : 'border-border text-text-muted hover:border-border-bright'
                    )}
                  >
                    {lang.charAt(0).toUpperCase() + lang.slice(1)}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="mb-1.5 block text-sm font-medium text-text">Java Version</label>
              <select
                value={form.javaVersion}
                onChange={(e) => setForm({ ...form, javaVersion: e.target.value })}
                className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm text-text focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
              >
                {javaVersions.map((v) => (
                  <option key={v} value={v}>Java {v}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="mb-3 block text-sm font-medium text-text">Build Tool</label>
              <div className="space-y-2">
                {compilers.map((c) => (
                  <button
                    key={c.value}
                    onClick={() => setForm({ ...form, compiler: c.value })}
                    className={cn(
                      'flex w-full items-center gap-3 rounded-lg border px-4 py-3 text-left transition-colors',
                      form.compiler === c.value
                        ? 'border-primary bg-primary/5'
                        : 'border-border hover:border-border-bright hover:bg-surface-hover'
                    )}
                  >
                    <div className={cn(
                      'flex h-4 w-4 shrink-0 items-center justify-center rounded-full border',
                      form.compiler === c.value
                        ? 'border-primary bg-primary'
                        : 'border-border'
                    )}>
                      {form.compiler === c.value && <div className="h-2 w-2 rounded-full bg-white" />}
                    </div>
                    <div>
                      <p className="text-sm font-medium text-text">{c.label}</p>
                      <p className="text-xs text-text-muted">{c.description}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-4">
            <label className="mb-3 block text-sm font-medium text-text">Project Source</label>
            <div className="space-y-2">
              {[
                { value: 'blank' as const, label: 'Blank Project', description: 'Start from scratch with a clean template' },
                { value: 'zip' as const, label: 'Upload ZIP', description: 'Import from a ZIP archive (coming soon)' },
                { value: 'github' as const, label: 'GitHub Repository', description: 'Clone from a GitHub repo (coming soon)' },
              ].map((opt) => (
                <button
                  key={opt.value}
                  onClick={() => opt.value === 'blank' && setForm({ ...form, source: opt.value })}
                  disabled={opt.value !== 'blank'}
                  className={cn(
                    'flex w-full items-center gap-3 rounded-lg border px-4 py-3 text-left transition-colors',
                    form.source === opt.value
                      ? 'border-primary bg-primary/5'
                      : 'border-border hover:border-border-bright hover:bg-surface-hover',
                    opt.value !== 'blank' && 'cursor-not-allowed opacity-50'
                  )}
                >
                  <div className={cn(
                    'flex h-4 w-4 shrink-0 items-center justify-center rounded-full border',
                    form.source === opt.value
                      ? 'border-primary bg-primary'
                      : 'border-border'
                  )}>
                    {form.source === opt.value && <div className="h-2 w-2 rounded-full bg-white" />}
                  </div>
                  <div>
                    <p className="text-sm font-medium text-text">{opt.label}</p>
                    <p className="text-xs text-text-muted">{opt.description}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      {error && (
        <div className="mt-4 rounded-lg border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
          {error}
        </div>
      )}

      {/* Navigation */}
      <div className="mt-6 flex items-center justify-between">
        <button
          onClick={() => setStep(step - 1)}
          disabled={step === 0}
          className="inline-flex items-center gap-2 rounded-lg border border-border px-4 py-2 text-sm text-text-muted transition-colors hover:bg-surface disabled:opacity-50"
        >
          <ArrowLeft className="h-4 w-4" />
          Previous
        </button>
        {step < steps.length - 1 ? (
          <button
            onClick={() => setStep(step + 1)}
            disabled={!canProceed()}
            className="inline-flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary-hover disabled:opacity-50"
          >
            Next
            <ArrowRight className="h-4 w-4" />
          </button>
        ) : (
          <button
            onClick={handleCreate}
            disabled={!canProceed() || isCreating}
            className="inline-flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary-hover disabled:opacity-50"
          >
            {isCreating ? 'Creating...' : 'Create Project'}
          </button>
        )}
      </div>
    </div>
  )
}
